```
namespace MyCustomMod
{
 public class MyMod : IMod
 {
 public static ILog Log { get; } = LogManager. GetLogger(nameof(MyMod)).SetShowsErrorsInUI(false);

private void MyMethod()
 {
 string formatted = "formatted";
 // Good: Plain message
 Log. Debug("This is just a message");

// Good: Formatted lightweight message
 // This exists to avoid allocations in string. Format() substitution when this method is filtered out by effectivenessLevel
 Log. DebugFormat("This is a {0}", formatted);

// BAD: This will execute DumpSlowLargeData regardless of the log effectiveness
 Log. DebugFormat("This is a heavy one {0}", DumpSlowLargeData());

// Good: Instead you could do this in the cases you need to
 if (Log.isDebugEnabled)
 Log. DebugFormat("This is a heavy one {0}", DumpSlowLargeData());

//You can print the trace with your log line
 Log.logStackTrace = true;
 Log. Debug("Your trace message");
 Log.logStackTrace = false;

// You can indent the log in a scope
 using (Log.indent.scoped)
 {
 Log. Info("I will be indented by a few spaces compared to the previous log");
 }// log indentation scope ends here
 }
 }
}

